105: func ParseURL(endpoint string) (string, error) {
106: 	if endpoint == "" {
107: 		return "", fmt.Errorf("missing URL from datasource configuration")
108: 	}
109: 
110: 	u, err := url.Parse(endpoint)
111: 	if err != nil {
112: 		return "", fmt.Errorf("bad URL : %s", err)
113: 	}
114: 
115: 	addr := u.Host
116: 	if u.Port() == "" {
117: 		addr += ":443"
118: 	}
119: 
120: 	// If the user has specified an address with no scheme it can still be valid
121: 	// So we use the raw URL value
122: 	if u.Host == "" {
123: 		addr = endpoint
124: 	}
125: 
126: 	return addr, nil
127: }
